use std::io;
use std::str::FromStr;

fn get_num() -> usize {
    let mut input = String::new();

    io::stdin().read_line(&mut input).expect("");

    usize::from_str(input.trim()).unwrap()
}

fn get_string() -> String {
    let mut input = String::new();

    io::stdin().read_line(&mut input).expect("");

    input.trim().to_string()
}

fn main() {
    let n = get_num();

    let mut v = vec![0; 10];
    for _ in 0..4 {
        let s = get_string();

        for c in s.chars() {
            if c == '.' {
                continue;
            }
            v[c.to_digit(10).unwrap() as usize] += 1;
        }
    }

    let mx = v.iter().max().unwrap();

    if *mx > 2 * n {
        println!("NO");
    } else {
        println!("YES");
    }
}
